#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int days[30];
        for (int i = 0; i < 30; i++) {
            scanf("%d", &days[i]);
        }
        int consecutiveDays = 0;
        for (int i = 0; i < 30; i++) {
            if (days[i] == 1) {
                consecutiveDays++;
                if (consecutiveDays > 5) {
                    printf("#coderlifematters\n");
                    break;
                }
            } else {
                consecutiveDays = 0;
            }
        }
        if (consecutiveDays <= 5) {
            printf("#allcodersarefun\n");
        }
    }
    return 0;
}

